// hooks/useMediaQuery.ts
import { useSyncExternalStore } from 'react';

const getSnapshot = (query: string) => () =>
  typeof window !== 'undefined' && window.matchMedia(query).matches;

const getServerSnapshot = (fallback: boolean) => () => fallback;

const subscribe = (query: string) => (callback: () => void) => {
  const mql = window.matchMedia(query);
  mql.addEventListener('change', callback);
  return () => mql.removeEventListener('change', callback);
};

export function useMediaQuery(query: string, ssrFallback = false): boolean {
  return useSyncExternalStore(
    subscribe(query),
    getSnapshot(query),
    getServerSnapshot(ssrFallback),
  );
}

// hooks/useBreakpoint.ts
import { useMediaQuery } from './useMediaQuery';

export type Breakpoint = 'mobile' | 'tablet' | 'desktop' | 'wide';

export function useBreakpoint(ssrDefault: Breakpoint = 'desktop'): Breakpoint {
  const isMobile = useMediaQuery('(max-width: 767px)', ssrDefault === 'mobile');
  const isTablet = useMediaQuery('(min-width: 768px) and (max-width: 1023px)', ssrDefault === 'tablet');
  const isWide = useMediaQuery('(min-width: 1920px)', ssrDefault === 'wide');
  if (isMobile) return 'mobile';
  if (isTablet) return 'tablet';
  if (isWide) return 'wide';
  return 'desktop';
}

// components/AppShell.tsx
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Sidebar } from './Sidebar';
import { BottomNav } from './BottomNav';
import { SidebarRail } from './SidebarRail';

export function AppShell({ children, ssrLayout }: { children: React.ReactNode; ssrLayout: Breakpoint }) {
  const bp = useBreakpoint(ssrLayout);
  return (
    <div className="min-h-dvh flex" data-layout={bp}>
      {bp === 'mobile' ? null : bp === 'tablet' ? <SidebarRail /> : <Sidebar />}
      <main className="flex-1 pb-[env(safe-area-inset-bottom)]">{children}</main>
      {bp === 'mobile' && <BottomNav />}
    </div>
  );
}

