/* app/globals.css */
:root {
  /* Major Third scale (1.25) with fluid clamps */
  /* Each step: clamp(min, preferred-base + vw-multiplier, max) */
  /* Min targets 320px viewport, max targets 1920px viewport */
  --step--2: clamp(0.6944rem, 0.6736rem + 0.1042vw, 0.7813rem);
  --step--1: clamp(0.8333rem, 0.8021rem + 0.1563vw, 0.9375rem);
  --step-0:  clamp(1rem, 0.9583rem + 0.2083vw, 1.125rem);   /* body */
  --step-1:  clamp(1.2rem, 1.1417rem + 0.2917vw, 1.4063rem); /* h6 */
  --step-2:  clamp(1.44rem, 1.36rem + 0.4vw, 1.7578rem);     /* h5 */
  --step-3:  clamp(1.728rem, 1.6173rem + 0.5536vw, 2.1973rem);/* h4 */
  --step-4:  clamp(2.0736rem, 1.9216rem + 0.7602vw, 2.7466rem);/* h3 */
  --step-5:  clamp(2.4883rem, 2.2812rem + 1.0358vw, 3.4332rem);/* h2 */
  --step-6:  clamp(2.986rem, 2.7042rem + 1.4088vw, 4.2915rem); /* h1 */

  /* Line-height pairs — tighter for headings, looser for body */
  --leading-tight: 1.1;
  --leading-snug: 1.25;
  --leading-normal: 1.6;
  --leading-loose: 1.75;

  /* Measure (line length) */
  --measure: 65ch;
}

@layer base {
  html { font-size: 100%; /* respect user setting */ }
  body { font-size: var(--step-0); line-height: var(--leading-normal); font-family: ui-sans-serif, system-ui, sans-serif; }
  h1 { font-size: var(--step-6); line-height: var(--leading-tight); letter-spacing: -0.02em; }
  h2 { font-size: var(--step-5); line-height: var(--leading-tight); letter-spacing: -0.015em; }
  h3 { font-size: var(--step-4); line-height: var(--leading-snug); letter-spacing: -0.01em; }
  h4 { font-size: var(--step-3); line-height: var(--leading-snug); }
  h5 { font-size: var(--step-2); line-height: var(--leading-snug); }
  h6 { font-size: var(--step-1); line-height: var(--leading-snug); }
  small, .text-small { font-size: var(--step--1); }
  .text-xs { font-size: var(--step--2); }
  p, li { max-width: var(--measure); overflow-wrap: anywhere; }
}

