// hooks/useHoverCapable.ts — for JS-needed cases (e.g., conditional features)
import { useSyncExternalStore } from 'react';
export function useHoverCapable(): boolean {
  return useSyncExternalStore(
    (cb) => { const mql = window.matchMedia('(hover: hover) and (pointer: fine)'); mql.addEventListener('change', cb); return () => mql.removeEventListener('change', cb); },
    () => window.matchMedia('(hover: hover) and (pointer: fine)').matches,
    () => true, /* SSR fallback: assume hover capable for SEO/initial paint */
  );
}

// hooks/useKeyboardInset.ts
import { useEffect } from 'react';

export function useKeyboardInset() {
  useEffect(() => {
    if (!('visualViewport' in window) || !window.visualViewport) return;
    const vv = window.visualViewport;
    let raf = 0;

    const update = () => {
      const inset = Math.max(0, window.innerHeight - vv.height - vv.offsetTop);
      document.documentElement.style.setProperty('--keyboard-inset', `${inset}px`);
    };

    const onChange = () => {
      cancelAnimationFrame(raf);
      raf = requestAnimationFrame(update);
    };

    update();
    vv.addEventListener('resize', onChange);
    vv.addEventListener('scroll', onChange);
    window.addEventListener('orientationchange', onChange);

    return () => {
      cancelAnimationFrame(raf);
      vv.removeEventListener('resize', onChange);
      vv.removeEventListener('scroll', onChange);
      window.removeEventListener('orientationchange', onChange);
      document.documentElement.style.removeProperty('--keyboard-inset');
    };
  }, []);
}

