// components/SignupForm.tsx
'use client';
import { useKeyboardInset } from '@/hooks/useKeyboardInset';
import { useRef } from 'react';

export function SignupForm() {
  useKeyboardInset();
  const formRef = useRef<HTMLFormElement>(null);

  const scrollFocusedIntoView = (e: React.FocusEvent<HTMLInputElement>) => {
    // delay so layout settles after keyboard animation
    setTimeout(() => {
      e.target.scrollIntoView({ block: 'center', behavior: 'smooth' });
    }, 300);
  };

  return (
    <form ref={formRef} className="min-h-dvh flex flex-col" onSubmit={(e) => e.preventDefault()}>
      <div className="flex-1 overflow-y-auto px-4 pt-6" style={{ paddingBottom: 'calc(var(--keyboard-inset, 0px) + 6rem)' }}>
        <h1 className="text-2xl font-semibold mb-6">Create your account</h1>
        <div className="space-y-4">
          <label className="block">
            <span className="text-sm font-medium">Email</span>
            <input type="email" inputMode="email" autoComplete="email" required onFocus={scrollFocusedIntoView}
              className="mt-1 block w-full min-h-11 rounded border px-3 text-base" />
          </label>
          <label className="block">
            <span className="text-sm font-medium">Password</span>
            <input type="password" autoComplete="new-password" required onFocus={scrollFocusedIntoView}
              className="mt-1 block w-full min-h-11 rounded border px-3 text-base" />
          </label>
        </div>
      </div>

      {/* Sticky footer — translates up by keyboard inset on iOS */}
      <div
        className="sticky bottom-0 border-t bg-white px-4 py-3"
        style={{
          transform: 'translateY(calc(-1 * var(--keyboard-inset, 0px)))',
          paddingBottom: 'max(0.75rem, env(safe-area-inset-bottom))',
          transition: 'transform 200ms',
        }}
      >
        <button type="submit" className="w-full min-h-12 rounded-lg bg-black text-white font-medium">
          Continue
        </button>
      </div>
    </form>
  );
}

