// components/VideoPlayer.tsx
'use client';
import { useRef, useState, useEffect } from 'react';
import { Play, Pause, Volume2, Maximize2, X } from 'lucide-react';

export function VideoPlayer({ src, title, description }: { src: string; title: string; description: string }) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [playing, setPlaying] = useState(false);
  const [showControls, setShowControls] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => playing && setShowControls(false), 3000);
    return () => clearTimeout(t);
  }, [playing, showControls]);

  return (
    <div
      ref={containerRef}
      className="
        grid w-full bg-black text-white
        grid-rows-[auto_1fr] portrait:grid-cols-1
        landscape:grid-rows-1 landscape:grid-cols-[1fr] landscape:lg:grid-cols-[1fr_320px]
        landscape:h-dvh
      "
      onMouseMove={() => setShowControls(true)}
      onTouchStart={() => setShowControls((s) => !s)}
    >
      {/* Video container — aspect-ratio in portrait, fill in landscape */}
      <div className="relative bg-black portrait:aspect-video landscape:h-full">
        <video
          ref={videoRef}
          src={src}
          className="h-full w-full object-contain"
          playsInline
          onPlay={() => setPlaying(true)}
          onPause={() => setPlaying(false)}
        />
        {/* Controls overlay */}
        <div className={`
          absolute inset-x-0 bottom-0 z-10 bg-gradient-to-t from-black/80 to-transparent
          px-4 pt-12 pb-[max(1rem,env(safe-area-inset-bottom))]
          transition-opacity
          ${showControls ? 'opacity-100' : 'opacity-0 pointer-events-none'}
        `}>
          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={() => playing ? videoRef.current?.pause() : videoRef.current?.play()}
              aria-label={playing ? 'Pause' : 'Play'}
              className="flex h-11 w-11 items-center justify-center rounded-full bg-white/20 backdrop-blur"
            >
              {playing ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5" />}
            </button>
            <input type="range" min={0} max={100} defaultValue={0} aria-label="Scrub" className="flex-1 h-11" />
            <button type="button" aria-label="Volume" className="flex h-11 w-11 items-center justify-center">
              <Volume2 className="h-5 w-5" />
            </button>
            <button
              type="button"
              onClick={() => containerRef.current?.requestFullscreen()}
              aria-label="Fullscreen"
              className="flex h-11 w-11 items-center justify-center"
            >
              <Maximize2 className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>

      {/* Info pane — different placement per orientation */}
      <aside className="
        bg-white text-black p-4 overflow-y-auto
        landscape:hidden landscape:lg:block
      ">
        <h1 className="text-lg font-semibold">{title}</h1>
        <p className="mt-2 text-sm text-neutral-700">{description}</p>
      </aside>
    </div>
  );
}

