// hooks/useDeviceContext.ts
import { useSyncExternalStore } from 'react';

export type DeviceContext = 'mobile' | 'tablet-portrait' | 'tablet-landscape' | 'desktop';

function subscribeMql(query: string) {
  return (cb: () => void) => {
    const mql = window.matchMedia(query);
    mql.addEventListener('change', cb);
    return () => mql.removeEventListener('change', cb);
  };
}

export function useDeviceContext(ssrDefault: DeviceContext = 'desktop'): DeviceContext {
  const isMobile = useSyncExternalStore(
    subscribeMql('(max-width: 767px)'),
    () => window.matchMedia('(max-width: 767px)').matches,
    () => ssrDefault === 'mobile',
  );
  const isTabletPortrait = useSyncExternalStore(
    subscribeMql('(min-width: 768px) and (max-width: 1279px) and (orientation: portrait)'),
    () => window.matchMedia('(min-width: 768px) and (max-width: 1279px) and (orientation: portrait)').matches,
    () => ssrDefault === 'tablet-portrait',
  );
  const isTabletLandscape = useSyncExternalStore(
    subscribeMql('(min-width: 768px) and (max-width: 1279px) and (orientation: landscape)'),
    () => window.matchMedia('(min-width: 768px) and (max-width: 1279px) and (orientation: landscape)').matches,
    () => ssrDefault === 'tablet-landscape',
  );
  if (isMobile) return 'mobile';
  if (isTabletPortrait) return 'tablet-portrait';
  if (isTabletLandscape) return 'tablet-landscape';
  return 'desktop';
}

