'use client';
import { useDeviceContext } from '@/hooks/useDeviceContext';
import { useState } from 'react';

export function ProjectDashboard({ ssrDevice, projects }: { ssrDevice: DeviceContext; projects: Project[] }) {
  const device = useDeviceContext(ssrDevice);
  const [selectedId, setSelectedId] = useState<string | null>(projects[0]?.id ?? null);
  const [showList, setShowList] = useState(device === 'mobile' ? true : true);
  const selected = projects.find((p) => p.id === selectedId);

  if (device === 'mobile') {
    return showList ? (
      <ProjectList projects={projects} onSelect={(id) => { setSelectedId(id); setShowList(false); }} />
    ) : (
      <ProjectDetail project={selected!} onBack={() => setShowList(true)} />
    );
  }

  if (device === 'tablet-portrait' || device === 'tablet-landscape') {
    return (
      <div className="grid h-dvh grid-cols-[40%_1fr] divide-x">
        <ProjectList projects={projects} onSelect={setSelectedId} activeId={selectedId} touchOptimized />
        {selected && <ProjectDetail project={selected} />}
      </div>
    );
  }

  // desktop
  return (
    <div className="grid h-dvh grid-cols-[20rem_1fr_22rem] divide-x">
      <ProjectList projects={projects} onSelect={setSelectedId} activeId={selectedId} />
      {selected && <ProjectDetail project={selected} />}
      {selected && <ProjectInspector project={selected} />}
    </div>
  );
}

