// hooks/usePaneLayout.ts
import { useEffect, useState } from 'react';
import { useBreakpoint } from './useBreakpoint';

type Layout = { folder: number; detail: number; inspector: number };
const DEFAULTS: Record<string, Layout> = {
  desktop: { folder: 240, detail: 0, inspector: 320 },
  tablet: { folder: 280, detail: 0, inspector: 0 },
  mobile: { folder: 0, detail: 0, inspector: 0 },
};

export function usePaneLayout() {
  const bp = useBreakpoint();
  const cls = bp === 'mobile' ? 'mobile' : bp === 'tablet' ? 'tablet' : 'desktop';
  const [layout, setLayout] = useState<Layout>(DEFAULTS[cls]);

  useEffect(() => {
    const stored = localStorage.getItem(`panes-${cls}`);
    if (stored) try { setLayout(JSON.parse(stored)); } catch {}
  }, [cls]);

  const save = (next: Layout) => {
    setLayout(next);
    localStorage.setItem(`panes-${cls}`, JSON.stringify(next));
  };

  return { layout, save, viewportClass: cls };
}

// components/Resizer.tsx
export function Resizer({ onResize, value, min, max, label }: {
  onResize: (v: number) => void;
  value: number;
  min: number;
  max: number;
  label: string;
}) {
  const onPointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    const startX = e.clientX;
    const startValue = value;
    let raf = 0;
    let latest = value;
    const onMove = (ev: PointerEvent) => {
      latest = Math.max(min, Math.min(max, startValue + (ev.clientX - startX)));
      cancelAnimationFrame(raf);
      raf = requestAnimationFrame(() => onResize(latest));
    };
    const onUp = () => {
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  };

  const onKeyDown = (e: React.KeyboardEvent) => {
    const step = e.shiftKey ? 50 : 5;
    if (e.key === 'ArrowLeft') onResize(Math.max(min, value - step));
    if (e.key === 'ArrowRight') onResize(Math.min(max, value + step));
    if (e.key === 'Home') onResize(min);
    if (e.key === 'End') onResize(max);
  };

  return (
    <div
      role="separator"
      aria-orientation="vertical"
      aria-label={label}
      aria-valuenow={value}
      aria-valuemin={min}
      aria-valuemax={max}
      tabIndex={0}
      onPointerDown={onPointerDown}
      onKeyDown={onKeyDown}
      className="
        w-1 cursor-col-resize bg-neutral-200 hover:bg-blue-400 focus-visible:bg-blue-400 focus-visible:outline-none
        before:absolute before:inset-y-0 before:-inset-x-1 relative
        @media (pointer: coarse) { w-2 }
      "
    />
  );
}

// components/MailLayout.tsx
export function MailLayout({ folder, detail, inspector }: { folder: React.ReactNode; detail: React.ReactNode; inspector: React.ReactNode }) {
  const { layout, save, viewportClass } = usePaneLayout();
  const gridStyle =
    viewportClass === 'desktop'
      ? { gridTemplateColumns: `${layout.folder}px 4px 1fr 4px ${layout.inspector}px` }
      : viewportClass === 'tablet'
      ? { gridTemplateColumns: `${layout.folder}px 4px 1fr` }
