      <main className="overflow-y-auto">{detail}</main>
      {viewportClass === 'desktop' && <Resizer value={layout.inspector} min={240} max={480} label="Resize inspector" onResize={(v) => save({ ...layout, inspector: v })} />}
      {viewportClass === 'desktop' && <aside className="overflow-y-auto border-l">{inspector}</aside>}
    </div>
  );
}

// components/PriorityTable.tsx
import { useState } from 'react';

type Col<T> = { key: keyof T; label: string; priority: 1 | 2 | 3 | 4 | 5; render?: (row: T) => React.ReactNode; numeric?: boolean };

export function PriorityTable<T extends { id: string }>({ rows, cols, onSort, sortKey }: {
  rows: T[];
  cols: Col<T>[];
  onSort?: (key: keyof T) => void;
  sortKey?: keyof T;
}) {
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const toggle = (id: string) => setExpanded((s) => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; });

  return (
    <div className="@container/table w-full overflow-x-auto">
      <table className="w-full border-collapse text-sm">
        <thead className="sticky top-0 bg-white border-b">
          <tr>
            <th scope="col" className="w-11 p-2"><span className="sr-only">Select</span></th>
            {cols.map((c) => (
              <th
                key={String(c.key)}
                scope="col"
                data-priority={c.priority}
                className={`
                  px-3 py-2 text-left font-medium
                  ${c.numeric ? 'text-right' : ''}
                  ${c.priority >= 4 ? '@max-[1024px]/table:hidden' : ''}
                  ${c.priority >= 2 ? '@max-[480px]/table:hidden' : ''}
                `}
              >
                <button type="button" onClick={() => onSort?.(c.key)} className="font-medium hover:underline">
                  {c.label}{sortKey === c.key && ' ↓'}
                </button>
              </th>
            ))}
            <th scope="col" className="w-11 p-2 @min-[1024px]/table:hidden"><span className="sr-only">Expand</span></th>
          </tr>
        </thead>
        <tbody>
          {rows.map((row) => {
            const isExpanded = expanded.has(row.id);
            const hiddenCols = cols.filter((c) => c.priority >= 2); // approximated
            return (
              <>
                <tr key={row.id} className="border-b hover:bg-neutral-50">
                  <td className="w-11 p-2"><input type="checkbox" className="h-5 w-5" aria-label={`Select ${row.id}`} /></td>
                  {cols.map((c) => (
                    <td
                      key={String(c.key)}
                      data-priority={c.priority}
                      className={`
                        px-3 py-2 truncate max-w-[200px]
                        ${c.numeric ? 'text-right tabular-nums' : ''}
                        ${c.priority >= 4 ? '@max-[1024px]/table:hidden' : ''}
                        ${c.priority >= 2 ? '@max-[480px]/table:hidden' : ''}
                      `}
                      title={String(row[c.key])}
                    >
                      {c.render ? c.render(row) : String(row[c.key])}
                    </td>
                  ))}
                  <td className="w-11 p-2 @min-[1024px]/table:hidden">
                    <button
                      type="button"
                      onClick={() => toggle(row.id)}
                      aria-expanded={isExpanded}
                      aria-label={`Expand row ${row.id}`}
                      className="flex h-11 w-11 items-center justify-center"
                    >
                      <span className={`transition-transform ${isExpanded ? 'rotate-90' : ''}`}>▶</span>
                    </button>
                  </td>
                </tr>
                {isExpanded && (
                  <tr className="bg-neutral-50 @min-[1024px]/table:hidden">
                    <td colSpan={cols.length + 2} className="px-4 py-3">
                      <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-sm">
                        {hiddenCols.map((c) => (
                          <>
                            <dt key={`${String(c.key)}-dt`} className="font-medium text-neutral-600">{c.label}</dt>
                            <dd key={`${String(c.key)}-dd`}>{c.render ? c.render(row) : String(row[c.key])}</dd>
                          </>
                        ))}
                      </dl>
                    </td>
                  </tr>
                )}
              </>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

