'use client';
import { useState, useRef } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function DateInput({ name, value, onChange, label, required }: {
  name: string;
  value: string; // ISO YYYY-MM-DD
  onChange: (v: string) => void;
  label: string;
  required?: boolean;
}) {
  const isTouch = useMediaQuery('(pointer: coarse)', true);

  if (isTouch) {
    return (
      <label className="block">
        <span className="text-sm font-medium">{label}</span>
        <input
          type="date"
          name={name}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          required={required}
          autoComplete="bday"
          className="mt-1 block w-full min-h-12 rounded border px-3 text-base"
        />
      </label>
    );
  }

  return <DesktopDateInput name={name} value={value} onChange={onChange} label={label} required={required} />;
}

function DesktopDateInput({ name, value, onChange, label, required }: any) {
  const [m, setM] = useState(value?.slice(5, 7) ?? '');
  const [d, setD] = useState(value?.slice(8, 10) ?? '');
  const [y, setY] = useState(value?.slice(0, 4) ?? '');
  const dayRef = useRef<HTMLInputElement>(null);
  const yearRef = useRef<HTMLInputElement>(null);
  const hiddenRef = useRef<HTMLInputElement>(null);

  const commit = (mm = m, dd = d, yyyy = y) => {
    if (mm.length === 2 && dd.length === 2 && yyyy.length === 4) {
      const iso = `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;
      onChange(iso);
    }
  };

  const handleSegment = (val: string, max: number, setter: (v: string) => void, nextRef?: React.RefObject<HTMLInputElement>) => {
    const digits = val.replace(/\D/g, '').slice(0, max);
    setter(digits);
    if (digits.length === max && nextRef?.current) nextRef.current.focus();
  };

  return (
    <div>
      <label htmlFor={`${name}-mm`} className="text-sm font-medium">{label}</label>
      <div className="mt-1 flex items-center gap-1 min-h-11 rounded border bg-white px-2 focus-within:ring-2 focus-within:ring-blue-500">
        <input id={`${name}-mm`} aria-label="Month" inputMode="numeric" maxLength={2} placeholder="MM" value={m}
          onChange={(e) => handleSegment(e.target.value, 2, setM, dayRef)} onBlur={() => commit()}
          className="w-7 bg-transparent text-center tabular-nums outline-none" />
        <span aria-hidden>/</span>
        <input ref={dayRef} aria-label="Day" inputMode="numeric" maxLength={2} placeholder="DD" value={d}
          onChange={(e) => handleSegment(e.target.value, 2, setD, yearRef)} onBlur={() => commit()}
          className="w-7 bg-transparent text-center tabular-nums outline-none" />
        <span aria-hidden>/</span>
        <input ref={yearRef} aria-label="Year" inputMode="numeric" maxLength={4} placeholder="YYYY" value={y}
          onChange={(e) => handleSegment(e.target.value, 4, setY)} onBlur={() => commit()}
          className="w-12 bg-transparent text-center tabular-nums outline-none" />
      </div>
      {/* Hidden native input for autofill */}
      <input ref={hiddenRef} type="date" name={name} value={value} required={required} autoComplete="bday"
        onChange={(e) => { const iso = e.target.value; if (iso) { setY(iso.slice(0,4)); setM(iso.slice(5,7)); setD(iso.slice(8,10)); onChange(iso); } }}
        className="sr-only" tabIndex={-1} aria-hidden />
    </div>
  );
}

