        {/* Ultrawide 21:9 desktop */}
        {image.ultrawide.sources.map((s) => (
          <source key={s.type + '-uw'} media="(min-width: 1440px) and (min-aspect-ratio: 16/9)" srcSet={s.srcset} sizes={image.ultrawide.sizes} type={s.type} />
        ))}
        {/* Standard landscape desktop/tablet */}
