            [@media(min-width:1440px)_and_(min-aspect-ratio:16/9)]:aspect-[21/9]
            object-cover
          "
        />
      </picture>
      {children && <div className="absolute inset-0 flex items-end p-[clamp(1rem,5vw,4rem)]">{children}</div>}
    </section>
  );
}

