// components/MegaMenuNav.tsx
import { useState, useRef } from 'react';
import { navData } from '@/data/nav';
import Link from 'next/link';

export function MegaMenuNav() {
  const [open, setOpen] = useState<string | null>(null);
  const timeoutRef = useRef<number>();

  const handleEnter = (id: string) => {
    clearTimeout(timeoutRef.current);
    setOpen(id);
  };
  const handleLeave = () => {
    timeoutRef.current = window.setTimeout(() => setOpen(null), 300);
  };

  return (
    <nav aria-label="Primary" className="hidden xl:block border-b">
      <ul className="mx-auto flex max-w-7xl items-center gap-1 px-6">
        {navData.map((item) => (
          <li key={item.id} onMouseEnter={() => handleEnter(item.id)} onMouseLeave={handleLeave} onFocus={() => handleEnter(item.id)} onBlur={handleLeave}>
            <Link href={item.href} className="flex h-12 items-center px-4 hover:bg-neutral-100 focus-visible:outline-2 focus-visible:outline-blue-500"
              aria-expanded={open === item.id} aria-haspopup={item.children ? 'true' : undefined}
            >{item.label}</Link>
            {open === item.id && item.children && (
              <div className="absolute inset-x-0 z-50 border-b bg-white shadow-lg"
                onMouseEnter={() => handleEnter(item.id)} onMouseLeave={handleLeave}
              >
                <div className="mx-auto max-w-7xl grid grid-cols-4 gap-6 p-8">
                  {item.children.map((c) => (
                    <Link key={c.id} href={c.href} className="text-sm hover:underline">{c.label}</Link>
                  ))}
                </div>
              </div>
            )}
          </li>
        ))}
      </ul>
    </nav>
  );
}

// components/DrawerNav.tsx — focus-trapped drawer
import { useState, useEffect, useRef } from 'react';

export function DrawerNav() {
  const [open, setOpen] = useState(false);
  const drawerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => e.key === 'Escape' && setOpen(false);
    document.addEventListener('keydown', handler);
    document.body.style.overflow = 'hidden';
    return () => { document.removeEventListener('keydown', handler); document.body.style.overflow = ''; };
  }, [open]);

  return (
    <>
      <button type="button" onClick={() => setOpen(true)} aria-label="Open navigation" aria-expanded={open}
        className="flex h-12 w-12 items-center justify-center">☰</button>
      {open && (
        <>
          <div className="fixed inset-0 z-40 bg-black/50" onClick={() => setOpen(false)} />
          <aside ref={drawerRef} role="dialog" aria-modal="true" aria-label="Navigation"
            className="fixed inset-y-0 left-0 z-50 w-80 max-w-[85vw] bg-white shadow-xl overflow-y-auto"
            style={{ paddingTop: 'env(safe-area-inset-top)' }}
          >
            <nav className="p-4">{/* full nav tree */}</nav>
          </aside>
        </>
      )}
    </>
  );
}

