// components/AdaptiveDialog.tsx
'use client';
import { useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function AdaptiveDialog({ open, onClose, title, children, primaryAction }: {
  open: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  primaryAction?: { label: string; onClick: () => void };
}) {
  const bp = useBreakpoint();
  const dialogRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLElement | null>(null);
  const [dragY, setDragY] = useState(0);

  useEffect(() => {
    if (!open) return;
    triggerRef.current = document.activeElement as HTMLElement;
    document.body.style.overflow = 'hidden';
    const focusable = dialogRef.current?.querySelectorAll<HTMLElement>('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');
    focusable?.[0]?.focus();

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') { onClose(); return; }
      if (e.key === 'Tab' && focusable && focusable.length > 0) {
        const first = focusable[0], last = focusable[focusable.length - 1];
        if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
        else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
      }
    };
    document.addEventListener('keydown', onKey);
    return () => {
      document.body.style.overflow = '';
      document.removeEventListener('keydown', onKey);
      triggerRef.current?.focus();
    };
  }, [open, onClose]);

  if (!open) return null;

  const handleDragStart = (e: React.PointerEvent) => {
    if (bp !== 'mobile') return;
    const startY = e.clientY;
    const onMove = (ev: PointerEvent) => setDragY(Math.max(0, ev.clientY - startY));
    const onUp = (ev: PointerEvent) => {
      const delta = ev.clientY - startY;
      if (delta > 120) onClose(); else setDragY(0);
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  };

  const content = (
    <div className="fixed inset-0 z-50">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} aria-hidden />
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="dialog-title"
        className={`
          absolute bg-white shadow-2xl
          ${bp === 'mobile'
            ? 'inset-x-0 bottom-0 rounded-t-2xl max-h-[90dvh] overflow-y-auto'
            : 'inset-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-md rounded-xl max-h-[85dvh] overflow-y-auto'}
        `}
        style={bp === 'mobile' ? { transform: `translateY(${dragY}px)`, paddingBottom: 'env(safe-area-inset-bottom)' } : undefined}
      >
        {bp === 'mobile' && (
          <div className="flex justify-center py-3 cursor-grab touch-none" onPointerDown={handleDragStart}>
            <div className="h-1.5 w-10 rounded-full bg-neutral-300" aria-hidden />
          </div>
        )}
        <div className="flex items-center justify-between px-5 pt-2 pb-3 border-b">
          <h2 id="dialog-title" className="text-lg font-semibold">{title}</h2>
          <button type="button" onClick={onClose} aria-label="Close" className="flex h-11 w-11 items-center justify-center -mr-2">×</button>
        </div>
        <div className="px-5 py-4">{children}</div>
        {primaryAction && (
          <div className="sticky bottom-0 bg-white border-t px-5 py-3" style={{ paddingBottom: 'max(0.75rem, env(safe-area-inset-bottom))' }}>
            <button type="button" onClick={primaryAction.onClick} className="w-full min-h-12 rounded-lg bg-black text-white">{primaryAction.label}</button>
          </div>
        )}
      </div>
    </div>
  );

  return createPortal(content, document.body);
}

import { useEffect, useRef, useState } from 'react';

export function UltrawideMonitor3440X1440LayoutThatD() {
  const rootRef = useRef<HTMLDivElement>(null);
  const [compact, setCompact] = useState(false);

  useEffect(() => {
    const node = rootRef.current;
    if (!node) return;
    const observer = new ResizeObserver(([entry]) => setCompact(entry.contentRect.width < 560));
    observer.observe(node);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={rootRef} data-compact={compact} className="grid gap-3 data-[compact=true]:grid-cols-1 data-[compact=false]:grid-cols-[16rem_1fr]">
      <nav aria-label="Section navigation" className="overflow-x-auto whitespace-nowrap">{/* actions remain reachable on touch and keyboard */}</nav>
      <main className="min-w-0">{/* Ultrawide monitor (3440x1440) layout that doesn't stretch content into unreadable lines */}</main>
    </section>
  );
}

