// hooks/useUserPreferences.ts
import { useSyncExternalStore } from 'react';
import { createContext, useContext, useState, useEffect } from 'react';

function subscribeMql(q: string) {
  return (cb: () => void) => {
    const m = window.matchMedia(q);
    m.addEventListener('change', cb);
    return () => m.removeEventListener('change', cb);
  };
}

function matchSnapshot(q: string) {
  return () => window.matchMedia(q).matches;
}

export function useReducedMotion(ssrDefault = false) {
  return useSyncExternalStore(subscribeMql('(prefers-reduced-motion: reduce)'), matchSnapshot('(prefers-reduced-motion: reduce)'), () => ssrDefault);
}
export function usePrefersDark(ssrDefault = false) {
  return useSyncExternalStore(subscribeMql('(prefers-color-scheme: dark)'), matchSnapshot('(prefers-color-scheme: dark)'), () => ssrDefault);
}
export function usePrefersHighContrast(ssrDefault = false) {
  return useSyncExternalStore(subscribeMql('(prefers-contrast: more)'), matchSnapshot('(prefers-contrast: more)'), () => ssrDefault);
}
export function usePrefersReducedData(ssrDefault = false) {
  return useSyncExternalStore(subscribeMql('(prefers-reduced-data: reduce)'), matchSnapshot('(prefers-reduced-data: reduce)'), () => ssrDefault);
}

// context/PreferencesProvider.tsx
type Theme = 'system' | 'light' | 'dark';
type Prefs = { theme: Theme; motion: 'system' | 'off'; setTheme: (t: Theme) => void; setMotion: (m: 'system' | 'off') => void };
const Ctx = createContext<Prefs | null>(null);

export function PreferencesProvider({ children }: { children: React.ReactNode }) {
  const osDark = usePrefersDark();
  const osReduced = useReducedMotion();
  const [theme, setThemeState] = useState<Theme>('system');
  const [motion, setMotionState] = useState<'system' | 'off'>('system');

  useEffect(() => {
    const t = localStorage.getItem('theme') as Theme | null;
    const m = localStorage.getItem('motion') as 'system' | 'off' | null;
    if (t) setThemeState(t);
    if (m) setMotionState(m);
  }, []);

  useEffect(() => {
    const isDark = theme === 'dark' || (theme === 'system' && osDark);
    const reduced = motion === 'off' || (motion === 'system' && osReduced);
    document.documentElement.classList.toggle('dark', isDark);
    document.documentElement.classList.toggle('reduce-motion', reduced);
  }, [theme, osDark, motion, osReduced]);

  const setTheme = (t: Theme) => { setThemeState(t); localStorage.setItem('theme', t); };
  const setMotion = (m: 'system' | 'off') => { setMotionState(m); localStorage.setItem('motion', m); };

  return <Ctx.Provider value={{ theme, motion, setTheme, setMotion }}>{children}</Ctx.Provider>;
}

export const usePreferences = () => { const c = useContext(Ctx); if (!c) throw new Error('PreferencesProvider missing'); return c; };

