// components/ReorderableList.tsx (using dnd-kit conceptually)
'use client';
import { useState, useRef } from 'react';
import { GripVertical } from 'lucide-react';

type Item = { id: string; label: string };

export function ReorderableList({ items: initial }: { items: Item[] }) {
  const [items, setItems] = useState(initial);
  const [reorderingId, setReorderingId] = useState<string | null>(null);
  const [announcement, setAnnouncement] = useState('');
  const longPressRef = useRef<number>();

  const handlePointerDown = (e: React.PointerEvent, id: string) => {
    if (e.pointerType === 'touch') {
      longPressRef.current = window.setTimeout(() => {
        navigator.vibrate?.(50);
        // begin drag — actual implementation uses dnd-kit
      }, 300);
    } else {
      // immediate drag for mouse
    }
  };

  const handlePointerUp = () => {
    clearTimeout(longPressRef.current);
  };

  const handleKeyDown = (e: React.KeyboardEvent, id: string) => {
    const idx = items.findIndex((i) => i.id === id);
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      if (reorderingId === id) {
        setReorderingId(null);
        setAnnouncement(`Dropped at position ${idx + 1}`);
      } else {
        setReorderingId(id);
        setAnnouncement(`Grabbed ${items[idx].label}. Use arrow keys to reorder. Press space to drop.`);
      }
    }
    if (reorderingId !== id) return;

    if (e.key === 'ArrowUp' && idx > 0) {
      e.preventDefault();
      const next = [...items];
      [next[idx], next[idx - 1]] = [next[idx - 1], next[idx]];
      setItems(next);
      setAnnouncement(`Moved to position ${idx}`);
    }
    if (e.key === 'ArrowDown' && idx < items.length - 1) {
      e.preventDefault();
      const next = [...items];
      [next[idx], next[idx + 1]] = [next[idx + 1], next[idx]];
      setItems(next);
      setAnnouncement(`Moved to position ${idx + 2}`);
    }
    if (e.key === 'Escape') {
      setReorderingId(null);
      setAnnouncement('Cancelled reorder');
    }
  };

  return (
    <div>
      <div aria-live="polite" aria-atomic className="sr-only">{announcement}</div>
      <ul className="divide-y rounded-lg border bg-white">
        {items.map((item) => (
          <li
            key={item.id}
            className={`flex items-center gap-2 px-2 ${reorderingId === item.id ? 'bg-blue-50 ring-2 ring-blue-400' : ''}`}
          >
            <button
              type="button"
              aria-label={`Reorder ${item.label}`}
              aria-grabbed={reorderingId === item.id}
              onPointerDown={(e) => handlePointerDown(e, item.id)}
              onPointerUp={handlePointerUp}
              onKeyDown={(e) => handleKeyDown(e, item.id)}
              className="
                flex h-11 w-11 cursor-grab items-center justify-center text-neutral-400
                hover:text-neutral-700 focus-visible:outline-2 focus-visible:outline-blue-500
                touch-none
              "
            >
              <GripVertical className="h-5 w-5" />
            </button>
            <span className="flex-1 py-3">{item.label}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}

// components/Composer.tsx
'use client';
import { useEffect, useRef, useState } from 'react';
import { useKeyboardInset } from '@/hooks/useKeyboardInset'; // from responsive-006
import { Send } from 'lucide-react';

const MIN_HEIGHT = 44;
const MAX_HEIGHT = 160;

export function Composer({ onSend, listRef }: { onSend: (text: string) => void; listRef: React.RefObject<HTMLDivElement> }) {
  useKeyboardInset();
  const [value, setValue] = useState('');
  const taRef = useRef<HTMLTextAreaElement>(null);

  const autoGrow = () => {
    const ta = taRef.current;
    if (!ta) return;
    ta.style.height = 'auto';
    ta.style.height = `${Math.min(ta.scrollHeight, MAX_HEIGHT)}px`;
  };

  useEffect(autoGrow, [value]);

  useEffect(() => {
    if (!('visualViewport' in window) || !window.visualViewport) return;
    const onResize = () => {
      // when keyboard appears, jump list to bottom
      requestAnimationFrame(() => {
        if (listRef.current) listRef.current.scrollTop = listRef.current.scrollHeight;
      });
    };
    window.visualViewport.addEventListener('resize', onResize);
    return () => window.visualViewport?.removeEventListener('resize', onResize);
  }, [listRef]);

  const handleSend = () => {
    if (!value.trim()) return;
    onSend(value.trim());
    setValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey && !window.matchMedia('(pointer: coarse)').matches) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div
      className="sticky bottom-0 z-30 border-t bg-white"
      style={{
        transform: 'translateY(calc(-1 * var(--keyboard-inset, 0px)))',
        paddingBottom: 'max(0.5rem, env(safe-area-inset-bottom))',
        transition: 'transform 200ms',
      }}
    >
      <form onSubmit={(e) => { e.preventDefault(); handleSend(); }} className="flex items-end gap-2 px-3 pt-2">
        <textarea
          ref={taRef}
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Message"
          rows={1}
          aria-label="Message text"
          className="
            flex-1 resize-none rounded-2xl border border-neutral-300 bg-neutral-50
            px-3 py-2 text-base leading-snug focus:outline-2 focus:outline-blue-500
          "
          style={{ minHeight: MIN_HEIGHT, maxHeight: MAX_HEIGHT }}
        />
        <button
          type="submit"
          disabled={!value.trim()}
          aria-label="Send"
          className="flex h-11 w-11 items-center justify-center rounded-full bg-blue-500 text-white disabled:bg-neutral-300"
        >
          <Send className="h-5 w-5" />
        </button>
      </form>
    </div>
  );
}

