'use client';
import { useEffect, useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function ResizeIndicator() {
  const bp = useBreakpoint();
  const [prevBp, setPrevBp] = useState(bp);
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (bp !== prevBp) {
      setShow(true);
      const t = setTimeout(() => { setShow(false); setPrevBp(bp); }, 1500);
      return () => clearTimeout(t);
    }
  }, [bp, prevBp]);

  if (!show) return null;
  return (
    <div
      role="status"
      aria-live="polite"
      className="fixed top-4 left-1/2 -translate-x-1/2 z-50 rounded-full bg-black/80 px-3 py-1 text-xs text-white"
    >
