// components/AdaptiveInspector.tsx
'use client';
import { useState, useEffect, useRef } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { createPortal } from 'react-dom';

export function AdaptiveInspector({ selectedId, children }: { selectedId: string | null; children: React.ReactNode }) {
  const bp = useBreakpoint();
  const [open, setOpen] = useState(bp === 'desktop' || bp === 'wide');
  const [scrollPos, setScrollPos] = useState(0);
  const contentRef = useRef<HTMLDivElement>(null);

  // Auto-reveal on selection (narrow viewports only)
  useEffect(() => {
    if (selectedId && (bp === 'mobile' || bp === 'tablet')) setOpen(true);
  }, [selectedId, bp]);

  // Preserve scroll across mode changes
  useEffect(() => {
    if (contentRef.current && open) contentRef.current.scrollTop = scrollPos;
  }, [bp, open, scrollPos]);

  // Keyboard shortcut
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'i') {
        e.preventDefault();
        setOpen((o) => !o);
      }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, []);

  const saveScroll = () => {
    if (contentRef.current) setScrollPos(contentRef.current.scrollTop);
  };

  if (bp === 'desktop' || bp === 'wide') {
    return (
      <aside
        aria-label="Properties inspector"
        className={`
          flex-none border-l bg-white transition-[width]
          ${open ? 'w-80' : 'w-0 overflow-hidden'}
        `}
      >
        {open && (
          <div ref={contentRef} onScroll={saveScroll} className="h-full overflow-y-auto p-4">
            {children}
          </div>
        )}
      </aside>
    );
  }

  if (!open) return null;

  // Tablet: side overlay; Mobile: bottom sheet
  return createPortal(
    <>
      <div className="fixed inset-0 z-40 bg-black/50" onClick={() => { saveScroll(); setOpen(false); }} />
      <aside
        role="dialog"
        aria-modal="true"
        aria-label="Properties inspector"
        className={`
          fixed z-50 bg-white shadow-2xl
          ${bp === 'mobile'
            ? 'inset-x-0 bottom-0 rounded-t-2xl max-h-[80dvh]'
            : 'inset-y-0 right-0 w-96 max-w-[85vw]'}
        `}
        style={bp === 'mobile' ? { paddingBottom: 'env(safe-area-inset-bottom)' } : undefined}
      >
        <div ref={contentRef} onScroll={saveScroll} className="h-full overflow-y-auto p-4">
          {children}
        </div>
      </aside>
    </>,
    document.body,
  );
}

