          {rows.map((row) => (
            <tr key={row.ticker} className="hover:bg-neutral-50">
              <th
                scope="row"
                className={`
                  sticky left-0 z-10 bg-white px-3 py-2 text-left font-medium border-b
                  ${scrolled ? 'shadow-[2px_0_4px_rgba(0,0,0,0.08)]' : ''}
                `}
              >{row.ticker}</th>
              {row.values.map((v) => (
                <td key={v.date} className="px-3 py-2 text-right tabular-nums border-b">
                  <div>${v.price.toFixed(2)}</div>
                  <div className={`text-xs ${v.change >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                    {v.change >= 0 ? '+' : ''}{v.change.toFixed(2)}%
                  </div>
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// components/StepIndicator.tsx
import { Check } from 'lucide-react';

type Step = { id: string; label: string; description?: string };

export function StepIndicator({ steps, currentIdx, onJump }: {
  steps: Step[];
  currentIdx: number;
  onJump?: (idx: number) => void;
}) {
  const pct = ((currentIdx + 1) / steps.length) * 100;
  return (
    <div className="@container/stepper w-full">
      {/* Dots — mobile */}
      <div className="@min-[640px]/stepper:hidden">
        <div role="progressbar" aria-valuenow={currentIdx + 1} aria-valuemin={1} aria-valuemax={steps.length} aria-label={`Step ${currentIdx + 1} of ${steps.length}: ${steps[currentIdx].label}`}
          className="flex items-center gap-2"
        >
          <span className="text-sm font-medium">Step {currentIdx + 1} of {steps.length}</span>
          <div className="flex-1 h-1 rounded bg-neutral-200 overflow-hidden">
            <div className="h-full bg-blue-500 transition-[width]" style={{ width: `${pct}%` }} />
          </div>
        </div>
        <div className="mt-1 text-base font-semibold">{steps[currentIdx].label}</div>
      </div>

      {/* Compact stepper — tablet */}
      <ol className="hidden @min-[640px]/stepper:flex @min-[1024px]/stepper:hidden items-center gap-3">
        {steps.map((s, i) => (
          <li key={s.id} className="flex items-center gap-2">
            <button type="button" disabled={i > currentIdx} onClick={() => onJump?.(i)}
              aria-current={i === currentIdx ? 'step' : undefined}
              className={`
                flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium
                ${i < currentIdx ? 'bg-blue-500 text-white' : i === currentIdx ? 'bg-blue-100 text-blue-700 ring-2 ring-blue-500' : 'bg-neutral-200 text-neutral-500'}
              `}
            >{i < currentIdx ? <Check className="h-4 w-4" /> : i + 1}</button>
            <span className={`text-sm ${i === currentIdx ? 'font-medium' : 'text-neutral-600'}`}>{s.label}</span>
            {i < steps.length - 1 && <span className="text-neutral-300">→</span>}
          </li>
        ))}
      </ol>

      {/* Full stepper — desktop */}
      <ol className="hidden @min-[1024px]/stepper:grid grid-cols-5 gap-4">
        {steps.map((s, i) => (
          <li key={s.id} className="relative">
            <button type="button" disabled={i > currentIdx} onClick={() => onJump?.(i)}
              aria-current={i === currentIdx ? 'step' : undefined}
              className="flex w-full items-start gap-3 text-left"
            >
              <span className={`
                flex h-9 w-9 flex-none items-center justify-center rounded-full text-sm font-medium
                ${i < currentIdx ? 'bg-blue-500 text-white' : i === currentIdx ? 'bg-blue-100 text-blue-700 ring-2 ring-blue-500' : 'bg-neutral-200 text-neutral-500'}
              `}>{i < currentIdx ? <Check className="h-4 w-4" /> : i + 1}</span>
              <span className="min-w-0">
                <span className={`block text-sm font-medium ${i === currentIdx ? 'text-black' : 'text-neutral-700'}`}>{s.label}</span>
                {s.description && <span className="block text-xs text-neutral-500 mt-0.5">{s.description}</span>}
              </span>
            </button>
          </li>
        ))}
      </ol>
    </div>
  );
}

