// hooks/useNetworkQuality.ts
import { useEffect, useState } from 'react';

type NetworkQuality = 'fast' | 'slow' | 'unknown';

export function useNetworkQuality(): NetworkQuality {
  const [quality, setQuality] = useState<NetworkQuality>('unknown');
  useEffect(() => {
    // @ts-expect-error — connection is experimental
    const conn = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
    if (!conn) { setQuality('fast'); return; }
    const update = () => {
      const slow = conn.saveData || ['slow-2g', '2g', '3g'].includes(conn.effectiveType);
      setQuality(slow ? 'slow' : 'fast');
    };
    update();
    conn.addEventListener?.('change', update);
    return () => conn.removeEventListener?.('change', update);
  }, []);
  return quality;
}

// components/BackgroundVideoHero.tsx
'use client';
import { useEffect, useState, useRef } from 'react';
import Image from 'next/image';
import { useNetworkQuality } from '@/hooks/useNetworkQuality';
import { useReducedMotion, usePrefersReducedData } from '@/hooks/useUserPreferences';

export function BackgroundVideoHero({ video, poster, alt, children }: {
  video: { mp4: string; webm: string };
  poster: string;
  alt: string;
  children: React.ReactNode;
}) {
  const network = useNetworkQuality();
  const reducedMotion = useReducedMotion();
  const reducedData = usePrefersReducedData();
  const videoRef = useRef<HTMLVideoElement>(null);
  const [showVideo, setShowVideo] = useState(false);

  const canPlay = network === 'fast' && !reducedMotion && !reducedData;

  useEffect(() => {
    if (canPlay) setShowVideo(true);
  }, [canPlay]);

  // Pause on tab blur to save battery
  useEffect(() => {
    const onVis = () => {
      if (document.hidden) videoRef.current?.pause();
      else if (canPlay) videoRef.current?.play().catch(() => {});
    };
    document.addEventListener('visibilitychange', onVis);
    return () => document.removeEventListener('visibilitychange', onVis);
  }, [canPlay]);

  return (
    <section className="relative isolate min-h-dvh overflow-hidden bg-neutral-900 text-white">
      {/* Always-present image (poster + fallback) */}
      <Image
        src={poster}
        alt={alt}
        fill
        priority
        sizes="100vw"
        className={`object-cover transition-opacity duration-700 ${showVideo ? 'opacity-0' : 'opacity-100'}`}
      />
      {/* Video — only mounted if eligible */}
      {canPlay && (
        <video
          ref={videoRef}
          autoPlay
          loop
          muted
          playsInline
          preload="metadata"
          poster={poster}
          aria-hidden
          onCanPlay={() => setShowVideo(true)}
          className={`absolute inset-0 h-full w-full object-cover transition-opacity duration-700 ${showVideo ? 'opacity-100' : 'opacity-0'}`}
        >
          <source src={video.webm} type="video/webm" />
          <source src={video.mp4} type="video/mp4" />
        </video>
      )}
      <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent" aria-hidden />
      <div
        className="relative z-10 flex min-h-dvh items-end px-[clamp(1rem,5vw,4rem)]"
        style={{ paddingBottom: 'max(2rem, env(safe-area-inset-bottom))' }}
      >
        {children}
      </div>
    </section>
  );
}

// hooks/useScrollDirection.ts
import { useEffect, useState } from 'react';

export function useScrollDirection(threshold = 8, minScroll = 80): 'up' | 'down' {
  const [dir, setDir] = useState<'up' | 'down'>('up');
  useEffect(() => {
    let lastY = window.scrollY;
    let raf = 0;
    const onScroll = () => {
      if (raf) return;
      raf = requestAnimationFrame(() => {
        const y = window.scrollY;
        const delta = y - lastY;
        if (Math.abs(delta) > threshold && y > minScroll) {
          setDir(delta > 0 ? 'down' : 'up');
        }
        if (y <= minScroll) setDir('up');
        lastY = y;
        raf = 0;
      });
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => { window.removeEventListener('scroll', onScroll); cancelAnimationFrame(raf); };
  }, [threshold, minScroll]);
  return dir;
}

// components/AutoHideTopBar.tsx
'use client';
import { useScrollDirection } from '@/hooks/useScrollDirection';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function AutoHideTopBar({ children }: { children: React.ReactNode }) {
  const dir = useScrollDirection();
  const isDesktop = useMediaQuery('(min-width: 1024px)', true);
  const hide = !isDesktop && dir === 'down';

  return (
    <header
      className="sticky top-0 z-30 border-b bg-white/95 backdrop-blur"
      style={{
        transform: hide ? 'translateY(-100%)' : 'translateY(0)',
        transition: 'transform 200ms ease-out',
        paddingTop: 'env(safe-area-inset-top)',
      }}
    >
      {children}
    </header>
  );
}

