// hooks/useFoldable.ts — for JS-dependent logic
import { useSyncExternalStore } from 'react';

export function useFoldable() {
  return useSyncExternalStore(
    (cb) => {
      const h = window.matchMedia('(horizontal-viewport-segments: 2)');
      const v = window.matchMedia('(vertical-viewport-segments: 2)');
      h.addEventListener('change', cb);
      v.addEventListener('change', cb);
      return () => { h.removeEventListener('change', cb); v.removeEventListener('change', cb); };
    },
    () => {
      const h = window.matchMedia('(horizontal-viewport-segments: 2)').matches;
      const v = window.matchMedia('(vertical-viewport-segments: 2)').matches;
      return h ? 'horizontal-fold' : v ? 'vertical-fold' : 'no-fold';
    },
    () => 'no-fold',
  );
}
